INSERT INTO public.questions (id, level_id, story_text, question_text, options, correct_answer, success_message, order_index) VALUES
('e9e47d4c-dd29-44c2-abde-9e0bd339d232','00000000-0000-0000-0000-000000000001','BoBoiBoy dan Ochobot sedang di Pulau Rintis. Tiba-tiba Adu Du datang! BoBoiBoy kumpul kuasa untuk lawan.','BoBoiBoy ada 3 kuasa. Dia dapat 2 lagi. Berapa jumlah kuasa?','["4","5","6","7"]','5','Hebat! BoBoiBoy makin kuat!',1),
('0d3f05bc-85b0-4fd8-abd0-3de402a1a445','00000000-0000-0000-0000-000000000001','Ochobot nak bantu BoBoiBoy. Dia kira berapa bahan yang ada.','Ochobot ada 4 bahan. Dia guna 2. Berapa yang tinggal?','["1","2","3","4"]','2','Pandai! Ochobot suka kamu!',2),
('6852668d-1aa0-45f0-90bf-d6a8053a9796','00000000-0000-0000-0000-000000000001','Yaya dan Ying lari dari robot Adu Du. Mereka kena kira langkah!','Yaya langkah 5 kali. Ying langkah 3 kali. Berapa jumlah langkah?','["7","8","9","10"]','8','Lari laju! Kamu bijak!',3),
('64385969-4049-4ef8-9f32-ccfa92c6fa2e','00000000-0000-0000-0000-000000000001','Gopal takut tengok robot. Dia sorok di sebalik pokok.','Ada 6 pokok. Robot rosak 2 pokok. Berapa pokok yang tinggal?','["3","4","5","6"]','4','Bagus! Pokok selamat!',4),
('7efff732-7858-4835-ae83-8a81989c4c04','00000000-0000-0000-0000-000000000001','BoBoiBoy Petir panah robot Adu Du. Setiap panah kena robot!','BoBoiBoy tembak 7 panah. 3 kena robot. Berapa yang tak kena?','["3","4","5","6"]','4','Terus cuba! BoBoiBoy tak putus asa!',5),
('565f1b11-dc3b-4c6f-a8ec-0a5668b30df8','00000000-0000-0000-0000-000000000001','Adu Du suruh Probe kira berapa BoBoiBoy ada kawan.','BoBoiBoy ada 2 kawan lelaki dan 3 kawan perempuan. Berapa semua?','["4","5","6","7"]','5','Kamu kira dengan betul!',6),
('b1ca82b4-6311-411e-ad6a-61e0ea47a1a8','00000000-0000-0000-0000-000000000001','Ochobot terbang dan tengok dari atas. Dia kira robot Adu Du.','Ada 8 robot. BoBoiBoy kalahkan 3. Berapa robot yang tinggal?','["4","5","6","7"]','5','Syabas! BoBoiBoy menang!',7),
('ab8ab16d-ed48-4fce-ae45-760692a93f24','00000000-0000-0000-0000-000000000001','Mama Zila masak untuk budak-budak. Mereka nak makan selepas selamatkan Ochobot.','Mama Zila buat 9 cucur. Mereka makan 4. Berapa yang tinggal?','["4","5","6","7"]','5','Sedap! Kamu bijak macam Mama Zila!',8),
('edd172c1-847e-4032-a3a3-4d0de29ad3f9','00000000-0000-0000-0000-000000000001','BoBoiBoy kumpul kristal untuk bagi tenaga pada Ochobot.','BoBoiBoy jumpa 1 kristal di hutan dan 6 di pantai. Berapa semua?','["6","7","8","9"]','7','Ochobot gembira! Kamu hebat!',9),
('dd42ef3c-dd3d-4044-bbe6-da9db76c7c56','00000000-0000-0000-0000-000000000001','Ying berlari laju dan selamatkan Ochobot dari robot!','Ying lari 10 langkah. Dia rehat lepas 4 langkah. Berapa lagi?','["5","6","7","8"]','6','Laju macam Ying! Bagus!',10),
('1d568762-1d09-45b9-8399-41563b665d7f','00000000-0000-0000-0000-000000000001','Gopal tukar makanan jadi senjata! Dia kira banyak mana yang ada.','Gopal ada 3 keropok dan 4 gula-gula. Berapa semua?','["6","7","8","9"]','7','Kamu kira macam Gopal yang bijak!',11),
('46d09f43-44d0-4637-9047-b63a7dc943f9','00000000-0000-0000-0000-000000000001','BoBoiBoy angin tiup robot-robot. Mereka jatuh satu persatu!','Ada 8 robot berdiri. 5 jatuh. Berapa yang masih berdiri?','["2","3","4","5"]','3','Angin kencang! Kamu betul!',12),
('048baae9-caf9-424c-a0d6-3931b04e5f75','00000000-0000-0000-0000-000000000001','Yaya terbang dan nampak kapal Adu Du di langit.','Kapal ada 2 tingkap di kiri dan 4 di kanan. Berapa semua?','["5","6","7","8"]','6','Pandangan tajam macam Yaya!',13),
('8d29c71a-a86f-46b4-803c-da0a0afd790b','00000000-0000-0000-0000-000000000001','Probe dan Computer sengketa pasal berapa bintang di langit malam.','Probe kira 5 bintang. Computer kira 3 lagi. Berapa semua?','["7","8","9","10"]','8','Kamu lebih bijak dari Probe!',14),
('5760520f-3251-4bd5-a201-8e3069c7a5e8','00000000-0000-0000-0000-000000000001','BoBoiBoy tembak kilat pada robot. Ada yang rosak terus!','BoBoiBoy tembak 9 kali. 6 kena robot. Berapa yang terpesong?','["2","3","4","5"]','3','Tepat macam BoBoiBoy! Bagus!',15),
('3aef060e-9fbf-4309-b614-06d8aabc801e','00000000-0000-0000-0000-000000000001','Adu Du marah sebab rancangannya gagal. Dia kira berapa kali dia kalah.','Adu Du kalah 4 kali pagi dan 2 kali petang. Berapa semua?','["5","6","7","8"]','6','Ha! Adu Du memang kalah!',16),
('f292f23c-01c7-4020-84af-ef12a2efc86f','00000000-0000-0000-0000-000000000001','Ochobot sembuh dan bagi bintang kepada BoBoiBoy!','Ochobot bagi 3 bintang kuning dan 5 bintang merah. Berapa semua?','["7","8","9","10"]','8','Terima kasih Ochobot! Kamu hebat!',17),
('4d6f064b-b7fb-40b1-ac44-1c689af005aa','00000000-0000-0000-0000-000000000001','Tok Aba buat coklat untuk semua orang. Dia kira cawan yang ada.','Tok Aba ada 10 cawan. Dia guna 7. Berapa yang tinggal?','["2","3","4","5"]','3','Coklat Tok Aba paling sedap!',18),
('d8325f27-aedc-4a3d-9cf2-d5c42224f986','00000000-0000-0000-0000-000000000001','BoBoiBoy gabung semua kuasanya untuk serang Adu Du!','BoBoiBoy ada kuasa angin 2, petir 3, dan api 1. Berapa semua?','["5","6","7","8"]','6','Tiga dalam satu! Kamu bijak!',19),
('874dffdb-d3ba-4459-8f4a-70c0750f627d','00000000-0000-0000-0000-000000000001','Semua kawan BoBoiBoy bersatu untuk lawan Adu Du sekali lagi.','Ada 3 kawan lelaki dan 2 kawan perempuan. Berapa semua kawan?','["4","5","6","7"]','5','Bersatu teguh! Kamu betul!',20),
('0491ff9f-2fb7-454c-9ad6-395da37f8238','00000000-0000-0000-0000-000000000001','Yaya buat perisai pelindung. Dia kira berapa banyak yang boleh dilindungi.','Yaya boleh lindungi 4 orang. Ying boleh lindungi 4 orang. Berapa semua?','["6","7","8","9"]','8','Dua hero lebih kuat!',21),
('44181329-0611-4a14-aedf-41c216b2b1b2','00000000-0000-0000-0000-000000000001','Gopal makan banyak. Dia kira berapa makanan yang dia habiskan.','Gopal makan 6 cucur. Ada 2 lagi. Berapa semua yang ada tadi?','["7","8","9","10"]','8','Ha! Gopal memang suka makan!',22),
('dc7869ff-0636-4981-b919-656cf286a423','00000000-0000-0000-0000-000000000001','BoBoiBoy berjaya selamatkan Ochobot! Semua orang gembira.','Ada 5 orang gembira. 3 lagi datang. Berapa semua yang gembira?','["7","8","9","10"]','8','Misi berjaya! Kamu bijak!',23),
('a8174420-362f-400e-88d6-b62b4ae0de7d','00000000-0000-0000-0000-000000000001','Probe cuba baiki robot yang rosak. Dia kira berapa skru yang ada.','Ada 9 skru. Probe guna 5. Berapa skru yang tinggal?','["3","4","5","6"]','4','Probe kena belajar matematik macam kamu!',24),
('13a0c6a4-c5f9-43c6-bcea-bb2418f86319','00000000-0000-0000-0000-000000000001','Computer berikan markah kepada BoBoiBoy lepas menang.','BoBoiBoy dapat 3 markah pagi dan 6 markah petang. Berapa semua?','["7","8","9","10"]','9','Markah penuh! Kamu macam BoBoiBoy!',25),
('856172cd-e228-4c8d-9923-aa05c8733ef1','00000000-0000-0000-0000-000000000001','Adu Du rancang untuk balik dan serang lagi. Dia kira robot baru.','Adu Du ada 2 robot lama dan buat 5 robot baru. Berapa semua?','["6","7","8","9"]','7','Tapi BoBoiBoy pasti menang lagi!',26),
('a1d32c8b-9c18-4f7e-b593-f241d9e0825b','00000000-0000-0000-0000-000000000001','Tok Aba kasih semua orang minum coklat. Dia kira cawan.','Ada 8 orang. 3 dah minum. Berapa yang belum minum?','["4","5","6","7"]','5','Minum dulu! Kamu bijak!',27),
('fef15c40-be77-45e1-b5d6-13cd73c27af5','00000000-0000-0000-0000-000000000001','Ochobot terbang tinggi dan nampak semua dari atas.','Ochobot nampak 4 rumah di kiri dan 4 rumah di kanan. Berapa semua?','["6","7","8","9"]','8','Pandangan luas! Kamu betul!',28),
('8510bbc2-ff41-4fb9-9c4b-2c3b4ac4f04b','00000000-0000-0000-0000-000000000001','BoBoiBoy selamatkan semua orang! Dia kira berapa orang yang selamat.','BoBoiBoy selamatkan 5 orang pagi dan 4 orang petang. Berapa semua?','["7","8","9","10"]','9','Hero sejati! Tahniah kamu!',29),
('975417c0-28c6-4723-9627-33b29963d169','00000000-0000-0000-0000-000000000001','Tamat! BoBoiBoy menang dan Ochobot selamat. Semua orang bersorak!','Ada 10 orang bersorak. 2 dah balik. Berapa yang masih bersorak?','["6","7","8","9"]','8','Tahniah! Kamu berjaya macam BoBoiBoy!',30);
INSERT INTO public.questions (id, level_id, story_text, question_text, options, correct_answer, success_message, order_index) VALUES
('738808c8-09dd-4fab-a0ec-430791f68c96','00000000-0000-0000-0000-000000000002','BoBoiBoy Galaxy dan krew Kapal Spaceship bertembung dengan tentera Retak-na!','Kapal ada 45 peluru. Mereka tembak 23. Berapa yang tinggal?','["20","22","24","26"]','22','Tepat! Krew selamat!',1),
('f6f69d25-50ce-4961-b12d-71c8224de572','00000000-0000-0000-0000-000000000002','Kiki dan Ochobot kira stok makanan dalam kapal.','Ada 38 tin makanan. Mereka makan 15. Berapa yang tinggal?','["21","22","23","24"]','23','Cukup untuk perjalanan jauh!',2),
('22d3994f-b864-4941-8606-d073a4de23cb','00000000-0000-0000-0000-000000000002','BoBoiBoy Petir melancarkan serangan pada kapal musuh!','Kapal musuh ada 67 prajurit. 34 dah lari. Berapa yang tinggal?','["31","32","33","34"]','33','Musuh ketakutan!',3),
('09b7d5f7-39f9-4dd0-850e-c4c3f8dfed5e','00000000-0000-0000-0000-000000000002','Sai dan Shielda tolong Fang kira bintang untuk navigasi kapal.','Mereka kira 25 bintang di utara dan 43 di selatan. Berapa semua?','["66","67","68","69"]','68','Navigasi betul! Bagus!',4),
('c571e96a-1e61-4e7f-a259-6f5f96dc4e5d','00000000-0000-0000-0000-000000000002','Fang tunjukkan kekuatan bayang-bayang untuk selamatkan krew.','Fang ada 50 tenaga. Dia guna 28. Berapa yang tinggal?','["20","22","24","26"]','22','Bayang-bayang masih kuat!',5),
('e29be2ed-8d2e-4273-a2f7-d2b8649e6bc3','00000000-0000-0000-0000-000000000002','Adu Du ikut dalam kapal diam-diam dan cuba curi makanan.','Adu Du ambil 17 dari 60 tin makanan. Berapa yang tinggal?','["41","42","43","44"]','43','Tangkap Adu Du!',6),
('138d22c5-63d9-4fdb-9f01-7851ee347f2d','00000000-0000-0000-0000-000000000002','Kapal Galaxy tiba di planet baru. Mereka kira batu asing.','Jumpa 32 batu biru dan 45 batu merah. Berapa semua batu?','["75","76","77","78"]','77','Planet baru, matematik sama!',7),
('3c7b8b35-aa6b-4f89-9976-6375b7907082','00000000-0000-0000-0000-000000000002','BoBoiBoy Api tembak musuh yang menghampiri kapal!','Ada 80 musuh. BoBoiBoy Api kalahkan 37. Berapa yang tinggal?','["41","42","43","44"]','43','Api berkobar! Kamu betul!',8),
('e14983ef-442f-496c-9d94-3d6dcb45eaa9','00000000-0000-0000-0000-000000000002','Ochobot upgrade kuasa BoBoiBoy. Semua kru gembira!','Kuasa asal 55. Lepas upgrade jadi 55+33. Berapa jumlah?','["86","87","88","89"]','88','Upgrade berjaya!',9),
('0c0f6809-7a0b-42a3-b6c4-8fbebad134ab','00000000-0000-0000-0000-000000000002','Retak-na hantar 70 prajurit serang kapal Galaxy!','BoBoiBoy Kilat kalahkan 29. Berapa prajurit yang tinggal?','["39","40","41","42"]','41','Teruskan perjuangan!',10),
('2f78bc80-da2b-4d2f-9b22-4220cafe6b3d','00000000-0000-0000-0000-000000000002','Kiki masak makanan untuk krew yang lapar selepas perang.','Kiki masak 54 roti. Krew makan 26. Berapa yang tinggal?','["26","27","28","29"]','28','Sedap masakan Kiki!',11),
('609f4f26-5d8e-4c7a-afb4-4553ba668a61','00000000-0000-0000-0000-000000000002','Kapal Galaxy jumpa kapal lain yang perlukan bantuan di angkasa.','Kapal tu ada 36 penumpang. Mereka selamatkan 15 lagi. Berapa semua?','["49","50","51","52"]','51','Hero angkasa!',12),
('7c5c702e-c8ab-48df-adb3-c56a28b20146','00000000-0000-0000-0000-000000000002','BoBoiBoy Air membuat ribut untuk halang musuh.','Ada 90 titik air dalam ribut. 48 dah jatuh. Berapa yang tinggal?','["40","41","42","43"]','42','Ribut semakin kuat!',13),
('69d22c25-9e07-4e3a-afcf-cef8f38a9fcf','00000000-0000-0000-0000-000000000002','Fang dan BoBoiBoy gabung kuasa untuk serang ketua musuh!','Fang ada tenaga 43. BoBoiBoy ada 35. Berapa jumlah tenaga?','["76","77","78","79"]','78','Gabungan kuasa terhebat!',14),
('d1776d3c-ffa3-4988-8e83-50cf33201c20','00000000-0000-0000-0000-000000000002','Sai selamatkan penumpang dari kapal yang terbakar.','Ada 62 penumpang. Sai selamatkan 38. Berapa yang masih dalam bahaya?','["22","23","24","25"]','24','Cepat! Selamatkan semua!',15),
('7f1b3f45-ad0f-422a-b25f-eab26a6c3be3','00000000-0000-0000-0000-000000000002','Kapal Galaxy dapat bahan api baru dari planet aman.','Bahan api asal 40. Dapat tambah 47. Berapa semua?','["85","86","87","88"]','87','Kapal boleh terus terbang!',16),
('8d456b60-36cc-4286-8963-f07d3a48e8ec','00000000-0000-0000-0000-000000000002','BoBoiBoy Daun tumbuhkan pokok untuk lindungi krew.','Tumbuh 28 pokok di kiri dan 39 di kanan. Berapa semua pokok?','["65","66","67","68"]','67','Alam lindungi kita!',17),
('a180632b-95f1-45da-a41e-f73168da3e52','00000000-0000-0000-0000-000000000002','Kapal Galaxy hampir tiba di destinasi! Semua kru bersedia.','Destinasi tinggal 85 minit lagi. Dah melalui 46 minit. Berapa lagi?','["37","38","39","40"]','39','Hampir sampai! Teruskan!',18),
('a7f006c9-0d72-4c34-8845-03b1592ac798','00000000-0000-0000-0000-000000000002','Musuh besar muncul! BoBoiBoy gabung semua elemen.','Kuasa angin 25, api 33, petir 30. Berapa jumlah kuasa?','["86","87","88","89"]','88','Kuasa penuh! Menang!',19),
('31576b9c-8ac2-4f54-a1a9-975889758439','00000000-0000-0000-0000-000000000002','Retak-na berundur! Kapal Galaxy menang dalam perang angkasa!','Ada 100 bintang kemenangan. Krew dapat 63. Berapa yang tinggal?','["35","36","37","38"]','37','Kemenangan untuk Galaxy!',20),
('af181a45-c66b-4977-a772-e749310138be','00000000-0000-0000-0000-000000000002','Ochobot kira markah kemenangan untuk semua ahli krew.','Kiki dapat 24, Ying dapat 31, Yaya dapat 29. Berapa semua?','["82","83","84","85"]','84','Semua hero dapat markah tinggi!',21),
('b093b4ff-dd07-49b4-8305-bcff1796a9d8','00000000-0000-0000-0000-000000000002','Krew Galaxy buat pesta kemenangan di kapal!','Ada 55 orang dalam pesta. 18 pergi tidur. Berapa yang masih berpesta?','["35","36","37","38"]','37','Pesta terus! Kamu bijak!',22),
('612e0f97-5f37-4349-b9dd-15f443ec2e64','00000000-0000-0000-0000-000000000002','BoBoiBoy dapat berita ada planet lain yang perlukan bantuan.','Perjalanan ambil 72 jam. Dah pergi 38 jam. Berapa jam lagi?','["32","33","34","35"]','34','Terus pergi! Hero tak rehat!',23),
('ce113a90-c8dc-42b8-8367-25d0829520ef','00000000-0000-0000-0000-000000000002','Shielda buat perisai besar untuk lindungi kapal dari asteroid.','Asteroid ada 91. Perisai halang 56. Berapa yang masih datang?','["33","34","35","36"]','35','Perisai kuat! Kapal selamat!',24),
('47d316bd-a5d4-48fb-b356-91bec2198639','00000000-0000-0000-0000-000000000002','Fang latihan bersama semua orang untuk misi seterusnya.','Krew latihan 47 minit. Rehat 13 minit. Berapa minit latihan semua?','["58","59","60","61"]','60','Latihan keras bagi hasil!',25),
('4062668b-fdd0-435b-99c0-d080c7f100ff','00000000-0000-0000-0000-000000000002','BoBoiBoy selesai misi angkasa dan semua kru selamat!','Krew asal 30 orang. Selamatkan 47 orang lagi. Berapa semua?','["75","76","77","78"]','77','Misi berjaya! Tahniah!',26),
('92efdb29-b1f0-411d-acf8-04aa17de15eb','00000000-0000-0000-0000-000000000002','Kapal Galaxy balik ke bumi dengan penuh kebanggaan!','Perjalanan balik 83 minit. Dah 49 minit berlalu. Berapa lagi?','["32","33","34","35"]','34','Hampir sampai rumah!',27),
('69edd8ce-52be-40a1-9fdf-269df8929eda','00000000-0000-0000-0000-000000000002','Semua kawan-kawan BoBoiBoy tunggu dia di bumi!','Ada 20 kawan tunggu di bumi dan 18 di angkasawan. Berapa semua?','["36","37","38","39"]','38','Ramai kawan BoBoiBoy!',28),
('050a4afc-1e6f-4697-a7ee-a3715b35c6b4','00000000-0000-0000-0000-000000000002','BoBoiBoy turun dari kapal dan semua orang bersorak!','Ada 65 orang bersorak. 28 lagi datang kemudian. Berapa semua?','["91","92","93","94"]','93','Selamat datang balik hero!',29),
('e7a4761a-7fe5-406e-9cfe-2bc0bcf61d26','00000000-0000-0000-0000-000000000002','Misi angkasa selesai! BoBoiBoy galaxy menang dengan matematik!','Jumlah bintang yang dikumpul: 56 + 37 = ?','["91","92","93","94"]','93','Tahniah! Kamu berjaya!',30);
INSERT INTO public.questions (id, level_id, story_text, question_text, options, correct_answer, success_message, order_index) VALUES
('fcc3b3e4-5b6c-40b3-8892-31e98989175d','00000000-0000-0000-0000-000000000003','BoBoiBoy ada 7 elemen berbeza! Setiap elemen ada kuasa yang berbeza.','Setiap elemen ada 8 kuasa. Ada 7 elemen. Berapa jumlah kuasa?','["54","55","56","57"]','56','7 × 8 = 56! Kamu hebat!',1),
('86891de0-e2c2-4ae6-944b-4c23a691434d','00000000-0000-0000-0000-000000000003','BoBoiBoy bahagi kuasanya kepada kawan-kawan untuk lawan musuh.','56 unit kuasa dibahagi 8 orang. Setiap orang dapat berapa?','["6","7","8","9"]','7','56 ÷ 8 = 7! Bijak!',2),
('2fb7e3f8-b7df-49ff-a0a2-a09f8954a0fc','00000000-0000-0000-0000-000000000003','Ejen Ochobot kira tenaga dalam kristal yang dijumpai.','Jumpa 9 kristal. Setiap kristal ada 6 tenaga. Berapa semua tenaga?','["52","53","54","55"]','54','9 × 6 = 54! Tenaga penuh!',3),
('e5a75f16-4801-4962-88bf-d25c40822dd9','00000000-0000-0000-0000-000000000003','Fang bahagi latihan kepada semua pelajar kuasa di akademi.','72 pelajar dibahagi 9 kumpulan. Setiap kumpulan ada berapa pelajar?','["7","8","9","10"]','8','72 ÷ 9 = 8! Kumpulan sempurna!',4),
('68715971-d28f-4f77-9f8d-541a04c16584','00000000-0000-0000-0000-000000000003','BoBoiBoy Api menyalakan 7 api dalam masa yang sama!','Setiap api bakar 9 saat. Ada 7 api. Berapa jumlah saat?','["60","62","63","64"]','63','7 × 9 = 63! Api marak!',5),
('5fb0580f-8061-4479-931e-8ee4e52fc2d4','00000000-0000-0000-0000-000000000003','Kapal musuh datang dalam kumpulan. Krew kira berapa kesemuanya.','63 musuh dalam 7 kapal sama rata. Setiap kapal ada berapa musuh?','["7","8","9","10"]','9','63 ÷ 7 = 9! Kira betul!',6),
('d50e0b26-1c4d-4404-8769-08944e03f595','00000000-0000-0000-0000-000000000003','BoBoiBoy Tanah angkat batu besar untuk sekat jalan musuh.','Setiap batu wajah 8 meter. Angkat 6 batu. Berapa jumlah meter?','["46","47","48","49"]','48','6 × 8 = 48! Kuat macam bumi!',7),
('5b886485-9b4f-4d53-beeb-5441ec8c695e','00000000-0000-0000-0000-000000000003','Ying bahagi perisai masa kepada semua kawan-kawannya.','48 shield dibahagi 6. Setiap orang dapat berapa?','["6","7","8","9"]','8','48 ÷ 6 = 8! Ying suka kamu!',8),
('47ad2392-53fc-481c-9d72-d36826ff7877','00000000-0000-0000-0000-000000000003','BoBoiBoy Kilat tembak musuh berkali-kali dengan pantas!','Tembak 7 kali setiap minit. 9 minit berlalu. Berapa jumlah tembakan?','["61","62","63","64"]','63','7 × 9 = 63! Kilat pantas!',9),
('468288d9-8ad3-41df-ac69-e53370c60b90','00000000-0000-0000-0000-000000000003','Yaya bahagi senjata kepada pasukan yang bersedia untuk bertempur.','54 senjata untuk 9 pasukan. Setiap pasukan dapat berapa?','["5","6","7","8"]','6','54 ÷ 9 = 6! Sedia bertempur!',10),
('ad544404-fa42-4266-9057-e1dd4574e377','00000000-0000-0000-0000-000000000003','BoBoiBoy Air buat ombak besar untuk halang musuh di pantai.','Setiap ombak ada 8 meter tinggi. Buat 8 ombak. Berapa meter semua?','["62","63","64","65"]','64','8 × 8 = 64! Ombak ganas!',11),
('8242820f-1c17-4510-a35f-6f6afdef2695','00000000-0000-0000-0000-000000000003','Gopal bahagi makanan kepada semua orang yang lapar lepas perang.','64 makanan untuk 8 orang. Setiap orang dapat berapa?','["7","8","9","10"]','8','64 ÷ 8 = 8! Semua kenyang!',12),
('81838487-362c-40ad-8998-eefa7f8d7b22','00000000-0000-0000-0000-000000000003','BoBoiBoy Daun tumbuhkan hutan untuk sorok semua kawan daripada musuh.','Setiap baris ada 7 pokok. Ada 9 baris. Berapa jumlah pokok?','["61","62","63","64"]','63','7 × 9 = 63! Hutan lebat!',13),
('23faebb4-7d93-4de0-9db9-12fd4b1d05fa','00000000-0000-0000-0000-000000000003','Probe kira berapa lama perjalanan kapal musuh ke Pulau Rintis.','63 jam dibahagi 7 hari. Setiap hari berapa jam perjalanan?','["7","8","9","10"]','9','63 ÷ 7 = 9! Kira tepat!',14),
('802674be-0601-4252-b139-91b2943bba70','00000000-0000-0000-0000-000000000003','Semua elemen BoBoiBoy bergabung untuk serangan terakhir!','6 elemen × 9 tenaga setiap satu. Berapa jumlah tenaga?','["52","53","54","55"]','54','6 × 9 = 54! Kuasa gabungan!',15),
('ad6c2a93-8fc6-4a82-8097-265b6b291f4f','00000000-0000-0000-0000-000000000003','Retak-na cuba bahagi tentera dia kepada beberapa barisan.','81 tentera dibahagi 9 barisan. Setiap barisan ada berapa?','["8","9","10","11"]','9','81 ÷ 9 = 9! Tapi BoBoiBoy menang!',16),
('74a41ddf-32d4-4678-88d2-3f88676a63b3','00000000-0000-0000-0000-000000000003','Ochobot kira bintang kemenangan yang dikumpul oleh semua krew.','8 krew × 9 bintang setiap satu. Berapa jumlah bintang?','["70","71","72","73"]','72','8 × 9 = 72! Hebat krew Galaxy!',17),
('15405bad-6f9a-4a71-aa19-2159a0a6f948','00000000-0000-0000-0000-000000000003','BoBoiBoy bahagi kristal tenaga kepada semua ahli pasukan.','72 kristal untuk 8 ahli. Setiap ahli dapat berapa?','["7","8","9","10"]','9','72 ÷ 8 = 9! Adil dan tepat!',18),
('1fb8e6eb-ce49-4da6-8dcd-af7e01dc50ac','00000000-0000-0000-0000-000000000003','Sai kira berapa lama dia boleh kekalkan perisai tenaga tinggi.','Perisai bertahan 9 minit. Guna 8 kali. Berapa minit semua?','["70","71","72","73"]','72','9 × 8 = 72! Perisai hebat!',19),
('0e22bed1-8d3b-4e08-9dc6-7b95e24d6125','00000000-0000-0000-0000-000000000003','Krew Galaxy buat strategi untuk bahagi tugas dalam pertempuran besar.','90 tugas dibahagi 9 orang. Setiap orang dapat berapa tugas?','["9","10","11","12"]','10','90 ÷ 9 = 10! Strategi sempurna!',20),
('c3ff8e49-f929-4003-9f5b-864d27e95ba6','00000000-0000-0000-0000-000000000003','BoBoiBoy terbang dan serang musuh dari atas! Serangan bertubi-tubi!','Setiap pusingan 7 serangan. Buat 8 pusingan. Berapa semua serangan?','["54","55","56","57"]','56','7 × 8 = 56! Serangan dahsyat!',21),
('f65d9310-a01a-4b98-ba20-3fe611667f0e','00000000-0000-0000-0000-000000000003','Shielda kira berapa banyak pelindung yang perlu dibuat untuk krew.','56 pelindung untuk 7 orang. Setiap orang dapat berapa?','["7","8","9","10"]','8','56 ÷ 7 = 8! Semua terlindung!',22),
('14953803-f962-4a93-86c7-c90f0a698056','00000000-0000-0000-0000-000000000003','BoBoiBoy Petir melepaskan serangan muktamad pada boss musuh!','Serangan ada 9 peringkat. Setiap peringkat ada 8 halilintar. Berapa semua?','["70","71","72","73"]','72','9 × 8 = 72! Boss kalah!',23),
('9d444087-ac47-4d72-9ae8-361d5db07ec6','00000000-0000-0000-0000-000000000003','Kiki bahagi hadiah kepada semua krew yang menang dalam pertempuran.','72 hadiah untuk 9 orang. Setiap orang dapat berapa?','["7","8","9","10"]','8','72 ÷ 9 = 8! Hadiah untuk semua!',24),
('0ff3be5d-b632-4306-931d-e3d083aad2eb','00000000-0000-0000-0000-000000000003','BoBoiBoy menang! Semua elemen bergabung dalam satu kuasa terakhir.','7 elemen × 8 kuasa terakhir. Berapa jumlah kuasa?','["54","55","56","57"]','56','7 × 8 = 56! Menang!',25),
('78a95eaa-1724-432b-af35-cbcf56323060','00000000-0000-0000-0000-000000000003','Musuh lari! BoBoiBoy kira berapa musuh yang berjaya melarikan diri.','54 musuh lari. Dibahagi 6 arah. Setiap arah ada berapa musuh?','["7","8","9","10"]','9','54 ÷ 6 = 9! Musuh pengecut!',26),
('41dc042e-4fb9-4ca1-868f-6d13c5d45e19','00000000-0000-0000-0000-000000000003','Fang dan BoBoiBoy kira jumlah latihan yang mereka buat bersama.','6 bulan × 9 latihan sebulan. Berapa jumlah latihan?','["52","53","54","55"]','54','6 × 9 = 54! Kerja keras berbaloi!',27),
('504b7ac4-68fc-4aca-9140-8b8102264387','00000000-0000-0000-0000-000000000003','Krew Galaxy bahagi tugas untuk membina markas baru di angkasa.','63 kerja dibahagi 7 orang. Setiap orang buat berapa kerja?','["7","8","9","10"]','9','63 ÷ 7 = 9! Markas berjaya!',28),
('c2775a84-e74a-4421-b8bd-1687ff569aac','00000000-0000-0000-0000-000000000003','BoBoiBoy dapat kuasa baru selepas menang! Semua orang kagum.','Kuasa baru: 8 jenis × 8 tahap. Berapa jumlah tahap kuasa?','["62","63","64","65"]','64','8 × 8 = 64! Kuasa luar biasa!',29),
('b52dbed6-c009-48ef-82b9-4ffd2d28be1a','00000000-0000-0000-0000-000000000003','Tamat! BoBoiBoy adalah hero terhebat! Terima kasih kerana bantu!','64 bintang untuk 8 hero. Setiap hero dapat berapa bintang?','["7","8","9","10"]','8','Tahniah hero matematik!',30);
INSERT INTO public.questions (id, level_id, story_text, question_text, options, correct_answer, success_message, order_index) VALUES
('63193827-14f5-4e9c-95a3-d4c8da5fcee6','00000000-0000-0000-0000-000000000004','Ejen Ali misi pertama! Dia kena tangkap pencuri di pasar malam.','Ali ada 8 alat perisik. Dia dapat 5 lagi dari MATA. Berapa semua?','["11","12","13","14"]','13','8 + 5 = 13! Misi berjaya!',1),
('168587b7-9375-401f-8a56-f41dc4f5bf9f','00000000-0000-0000-0000-000000000004','Ejen Dos bantu Ali kesan pencuri. Mereka kira tapak kaki.','Ada 15 tapak kaki. 7 milik pencuri. Berapa yang bukan pencuri?','["6","7","8","9"]','8','15 - 7 = 8! Kesan bijak!',2),
('1648c320-970a-4e36-aa59-286d165af469','00000000-0000-0000-0000-000000000004','Ibu Ali masak untuk tenaga sebelum misi. Ali kena makan kenyang!','Ibu masak 12 lauk. Ali makan 5. Berapa yang tinggal?','["5","6","7","8"]','7','12 - 5 = 7! Makan dulu baru misi!',3),
('45a3c689-4881-405f-9cd6-a1f7dcf402d6','00000000-0000-0000-0000-000000000004','Ali guna MURI untuk kesan pencuri. MURI kesan beberapa laluan.','MURI kesan 9 laluan di utara dan 6 di selatan. Berapa semua?','["13","14","15","16"]','15','9 + 6 = 15! MURI canggih!',4),
('2d7c9a4b-866e-45ce-b943-e4c538c6d12d','00000000-0000-0000-0000-000000000004','Pencuri lari! Ali kejar dengan laju. Dia kira langkah dia.','Ali dah langkah 11 meter. Pencuri ada 17 meter ke hadapan. Berapa jauh lagi?','["5","6","7","8"]','6','17 - 11 = 6! Kejar lagi!',5),
('5c57b7a2-9dc2-43e5-a852-bbed24e0dcea','00000000-0000-0000-0000-000000000004','Ejen Zain beri maklumat kepada Ali tentang kawasan yang perlu dijaga.','Ada 7 kawasan barat dan 8 kawasan timur. Berapa semua kawasan?','["13","14","15","16"]','15','7 + 8 = 15! Kawasan dijaga!',6),
('81dba6ba-c6fa-4e71-a5c3-c52ba70ed465','00000000-0000-0000-0000-000000000004','Ali sorok di belakang kereta untuk tengok pencuri tidak nampak.','Ada 18 kereta di kawasan tu. Ali sorok di belakang 3 kereta. Berapa kereta yang Ali tak sorok?','["13","14","15","16"]','15','18 - 3 = 15! Ali bijak!',7),
('953374b9-0301-4a17-9f18-06ef40a733b3','00000000-0000-0000-0000-000000000004','MURI kesan isyarat dari pencuri! Ali dapat koordinat.','Koordinat: 6 arah ke kiri dan 7 arah ke atas. Berapa jumlah koordinat?','["12","13","14","15"]','13','6 + 7 = 13! Koordinat tepat!',8),
('0cac5f61-c4e1-431c-9f76-71a77b8fe1d7','00000000-0000-0000-0000-000000000004','Ali terjumpa kawan pencuri yang cuba halang dia!','Ada 16 penghalang. Ali dah lepasi 9. Berapa yang tinggal?','["6","7","8","9"]','7','16 - 9 = 7! Ali tak berhenti!',9),
('7741905e-8b95-4aa1-8c48-37d5ebab3818','00000000-0000-0000-0000-000000000004','Pencuri cuba sorok barangan yang dicuri dalam beberapa beg.','Ali jumpa 5 beg merah dan 8 beg hitam. Berapa semua beg?','["12","13","14","15"]','13','5 + 8 = 13! Jumpa semua beg!',10),
('9ad07e25-e6de-4410-b40d-6476dc020008','00000000-0000-0000-0000-000000000004','Ejen Dos halang pencuri dari belakang. Ali serbu dari hadapan!','Ada 14 pencuri. Dos tangkap 6. Berapa yang Ali perlu tangkap?','["7","8","9","10"]','8','14 - 6 = 8! Tangkap semua!',11),
('d9864373-ee6a-4034-a3aa-0c7ccfd746e4','00000000-0000-0000-0000-000000000004','Ali guna gadget istimewa dari MATA untuk kesan pencuri utama.','Gadget ada tenaga 20. Dah guna 11. Berapa tenaga yang tinggal?','["7","8","9","10"]','9','20 - 11 = 9! Tenaga cukup!',12),
('dc116e2a-3573-46e7-a065-d1c04664a3bf','00000000-0000-0000-0000-000000000004','Pencuri cuba bagi rasuah kepada Ali. Tapi Ali tak menerima!','Pencuri tawarkan 9 wang emas dan 4 permata. Berapa semua tawaran?','["12","13","14","15"]','13','9 + 4 = 13! Ali tolak semuanya!',13),
('92345eac-0357-40d8-805a-fb126d536d63','00000000-0000-0000-0000-000000000004','Ali berjaya tangkap pencuri! MATA bagi kredit kepada Ali.','Ali dapat 7 kredit dari Ejen Zain dan 9 dari MATA. Berapa semua?','["14","15","16","17"]','16','7 + 9 = 16! Kredit tinggi!',14),
('ce2186ae-23f9-47e5-91db-e9fb024f1ce1','00000000-0000-0000-0000-000000000004','Pencuri dimasukkan dalam lokap. Ali lapor kepada ketua MATA.','Ada 18 laporan. Ali dah siapkan 10. Berapa yang tinggal?','["7","8","9","10"]','8','18 - 10 = 8! Siapkan semua!',15),
('06f0154f-94a0-4d68-82e0-69bbba30beec','00000000-0000-0000-0000-000000000004','Ibu Ali bangga dengan kejayaan anaknya! Dia buat kek!','Kek ada 15 cerasa. Ali makan 6. Berapa yang tinggal?','["7","8","9","10"]','9','15 - 6 = 9! Selamat makan Ali!',16),
('8075629d-65b4-45e8-a541-39cff6879ac4','00000000-0000-0000-0000-000000000004','Ejen Ali dapat berita ada pencuri lain! Misi belum selesai.','MURI kesan 8 pencuri baru di kawasan A dan 5 di kawasan B. Berapa semua?','["12","13","14","15"]','13','8 + 5 = 13! Misi teruskan!',17),
('3624ddcb-89bc-4bd0-bf16-fac1063b9dd2','00000000-0000-0000-0000-000000000004','Ali panggil bantuan dari kawan-kawan ejen yang lain.','Ali panggil 4 ejen dari utara dan 9 ejen dari selatan. Berapa semua?','["12","13","14","15"]','13','4 + 9 = 13! Pasukan lengkap!',18),
('9c03d100-be65-447d-8d21-0a1e89ce7961','00000000-0000-0000-0000-000000000004','Pasukan Ali kepung kawasan pencuri dari semua arah!','Ada 17 arah kepungan. Ali cover 8 arah. Kawan cover selebihnya. Berapa kawan cover?','["7","8","9","10"]','9','17 - 8 = 9! Kepungan sempurna!',19),
('c1ea7204-64ca-47bf-a0c4-c7587fdc28a7','00000000-0000-0000-0000-000000000004','Semua pencuri ditangkap! Ali menang dalam misi pertamanya.','Tangkap 13 pencuri pertama dan 7 yang baru. Berapa semua pencuri ditangkap?','["18","19","20","21"]','20','13 + 7 = 20! Misi berjaya!',20),
('6478ce87-35ab-4621-a7eb-12c2b8fd7652','00000000-0000-0000-0000-000000000004','MATA bagi anugerah kepada Ali kerana berjaya dalam misi.','Ali dapat anugerah bernilai 16 mata. Dos dapat 8 mata. Berapa lebih Ali dari Dos?','["7","8","9","10"]','8','16 - 8 = 8! Ali nombor satu!',21),
('3aa1b50b-56ac-4479-8ef0-087bd4233443','00000000-0000-0000-0000-000000000004','Ali simpan semua gadget dalam bilik rahsianya.','Bilik ada ruang untuk 20 gadget. Ali ada 14. Berapa ruang yang tinggal?','["5","6","7","8"]','6','20 - 14 = 6! Ruang untuk gadget baru!',22),
('70d24dc4-157a-48c3-874f-729671bd0459','00000000-0000-0000-0000-000000000004','Ejen Dos ambil gambar sebagai kenangan selepas misi berjaya.','Dos ambil 9 gambar pagi dan 8 gambar petang. Berapa semua gambar?','["15","16","17","18"]','17','9 + 8 = 17! Kenangan indah!',23),
('d9acc9b3-f0be-455d-9273-8a6b3f93e195','00000000-0000-0000-0000-000000000004','Ibu Ali masak makanan kegemaran Ali untuk sambut kejayaan misi!','Ada 11 hidangan. 4 untuk Ali, selebihnya untuk keluarga. Berapa untuk keluarga?','["6","7","8","9"]','7','11 - 4 = 7! Makan bersama!',24),
('30094376-7e2e-4bfb-b7d1-2fc166627181','00000000-0000-0000-0000-000000000004','Ali baca fail misi untuk buat laporan kepada MATA.','Fail ada 19 muka surat. Ali baca 12. Berapa yang tinggal?','["6","7","8","9"]','7','19 - 12 = 7! Hampir siap!',25),
('fd7c9ec7-3826-45a5-ad0f-6795dcc0cd5c','00000000-0000-0000-0000-000000000004','Ejen Zain bagi pujian kepada Ali di hadapan semua ejen MATA.','Ada 6 ejen lelaki dan 7 ejen perempuan dalam bilik tu. Berapa semua?','["12","13","14","15"]','13','6 + 7 = 13! Semua kagum dengan Ali!',26),
('15cb0a2b-b1e5-4398-be28-5ff9795aa847','00000000-0000-0000-0000-000000000004','MURI beri maklumat tentang misi seterusnya kepada Ali.','MURI ada 15 fail misi. 8 sudah selesai. Berapa yang belum?','["6","7","8","9"]','7','15 - 8 = 7! Misi belum habis!',27),
('344ee7bd-e3fc-4c94-8ef8-5c385f78f1f7','00000000-0000-0000-0000-000000000004','Ali bersedia untuk misi seterusnya! Dia kumpul semua alat.','Ali ada 5 alat lama dan dapat 9 alat baru. Berapa semua alat?','["13","14","15","16"]','14','5 + 9 = 14! Sedia untuk misi!',28),
('bd3baf8b-c60c-4bad-86d6-e33e9f2441fa','00000000-0000-0000-0000-000000000004','Ibu Ali doakan keselamatan anaknya sebelum dia pergi misi.','Ali ada 16 doa dari ibu. Dos ada 8 doa. Berapa lebih Ali?','["7","8","9","10"]','8','16 - 8 = 8! Doa ibu kuat!',29),
('b36bb626-f256-480c-85cd-bbf3caf10976','00000000-0000-0000-0000-000000000004','Ejen Ali berjaya! MATA bangga ada ejen muda seperti dia!','Jumlah misi berjaya: 9 misi hari ini + 4 sebelumnya. Berapa semua?','["12","13","14","15"]','13','Tahniah Ejen Ali muda!',30);
INSERT INTO public.questions (id, level_id, story_text, question_text, options, correct_answer, success_message, order_index) VALUES
('55c8ceab-df0d-483f-afeb-441198dbbf14','00000000-0000-0000-0000-000000000005','Upin dan Ipin excited sambut Hari Raya! Opah masak banyak makanan.','Opah masak 8 kuih dan Mak Su buat 7 kuih. Berapa semua kuih?','["13","14","15","16"]','15','8 + 7 = 15! Banyaknya kuih!',1),
('25e163dc-0a15-469a-9bae-0f712a65dc50','00000000-0000-0000-0000-000000000005','Upin dan Ipin dapat duit raya dari semua orang yang datang.','Dapat 9 ringgit dari Opah dan 6 ringgit dari Mak Su. Berapa semua?','["13","14","15","16"]','15','9 + 6 = 15! Kaya raya!',2),
('a7ee2d81-da39-43aa-8ee8-5a122b874cdd','00000000-0000-0000-0000-000000000005','Mail jual mercun masa Hari Raya. Dia kira berapa yang laku.','Mail ada 18 mercun. Dah jual 9. Berapa yang tinggal?','["8","9","10","11"]','9','18 - 9 = 9! Lagi separuh!',3),
('b70c9392-8fac-49b7-a410-b976015d45d8','00000000-0000-0000-0000-000000000005','Mei Mei datang sambut Hari Raya bersama Upin dan Ipin!','Mereka bertiga main dan ada 5 kawan lain join. Berapa semua kawan?','["7","8","9","10"]','8','3 + 5 = 8! Ramai kawan!',4),
('11d8ab37-c794-4f75-bc22-ac3e0eaaa326','00000000-0000-0000-0000-000000000005','Upin dan Ipin tolong Opah angkat kuih ke meja untuk tetamu.','Ada 16 kuih di dapur. Dah bawa 7 ke meja. Berapa yang tinggal?','["8","9","10","11"]','9','16 - 7 = 9! Rajin tolong Opah!',5),
('2128cf42-2cf0-44e6-a65d-955263069aaa','00000000-0000-0000-0000-000000000005','Ehsan datang beraya dengan baju baru yang cantik!','Ehsan dapat 7 angpau dari kiri dan 8 dari kanan. Berapa semua?','["13","14","15","16"]','15','7 + 8 = 15! Syukur Ehsan!',6),
('37cf7297-5d75-43c2-9814-14689b4421e3','00000000-0000-0000-0000-000000000005','Jarjit buat lawak masa Hari Raya. Semua orang gelak!','Ada 12 orang dengar lawak. 5 dah balik. Berapa yang masih dengar?','["6","7","8","9"]','7','12 - 5 = 7! Kelakar Jarjit!',7),
('7672814f-f350-4f6f-aa97-d93c9ede75d3','00000000-0000-0000-0000-000000000005','Fizi makan banyak kuih raya. Perutnya dah penuh!','Fizi makan 6 kuih pagi dan 5 kuih petang. Berapa semua kuih Fizi makan?','["10","11","12","13"]','11','6 + 5 = 11! Perut Fizi bulat!',8),
('a9ef10b1-d169-4251-8cd9-288df03861e8','00000000-0000-0000-0000-000000000005','Upin dan Ipin pakai baju baru dan pergi rumah jiran beraya.','Mereka singgah 8 rumah pagi dan 6 rumah petang. Berapa semua rumah?','["12","13","14","15"]','14','8 + 6 = 14! Rajin beraya!',9),
('e0b32dbf-27d1-48df-8c2d-b2e8ff4b298b','00000000-0000-0000-0000-000000000005','Opah hitung duit untuk bagi kepada cucu-cucu dia.','Opah ada 20 ringgit. Bagi kepada 5 cucu sama rata. Setiap cucu dapat berapa?','["2","3","4","5"]','4','20 ÷ 5 = 4! Adil Opah!',10),
('ff01e9ba-eeaa-4218-930c-16f121854ba8','00000000-0000-0000-0000-000000000005','Kak Ros marah sikit sebab Upin Ipin buat bising masa orang tidur.','Ada 15 orang tidur. Upin Ipin kejutkan 6. Berapa yang masih tidur?','["8","9","10","11"]','9','15 - 6 = 9! Sssshh!',11),
('15cb5e67-e0b5-49e9-b4f8-cd66d2a59ddb','00000000-0000-0000-0000-000000000005','Upin Ipin tolong Mak Su susun kerusi untuk tetamu Hari Raya.','Ada 13 kerusi. Dah susun 8. Berapa yang belum disusun?','["4","5","6","7"]','5','13 - 8 = 5! Sikit lagi!',12),
('c9dbbff8-30da-4679-80db-38961e1f77f6','00000000-0000-0000-0000-000000000005','Tetamu datang beramai-ramai ke rumah Opah! Meriah sangat!','Pagi datang 9 tetamu. Petang datang 8 lagi. Berapa semua?','["15","16","17","18"]','17','9 + 8 = 17! Rumah Opah meriah!',13),
('e39005e7-e416-41c9-a424-3373c53208a4','00000000-0000-0000-0000-000000000005','Upin Ipin main bunga api bersama kawan-kawan pada malam Hari Raya.','Ada 18 bunga api. Dah bakar 11. Berapa yang tinggal?','["6","7","8","9"]','7','18 - 11 = 7! Cantiknya bunga api!',14),
('5b9d4db4-a102-43f5-a1b1-8d3981130d6d','00000000-0000-0000-0000-000000000005','Opah kira berapa banyak kuih yang tinggal selepas tetamu balik.','Opah buat 20 kuih. Tetamu habis makan 14. Berapa yang tinggal?','["5","6","7","8"]','6','20 - 14 = 6! Sedap kuih Opah!',15),
('9c0d5eb5-29c9-4a96-9ee8-24232aa61487','00000000-0000-0000-0000-000000000005','Mail jual lemang masa Hari Raya! Lemang dia sedap!','Mail masak 9 batang lemang. Jual 5. Berapa yang tinggal?','["3","4","5","6"]','4','9 - 5 = 4! Lemang laris!',16),
('de997d69-57b6-4138-8d5a-41777e834180','00000000-0000-0000-0000-000000000005','Upin Ipin pergi solat raya pagi-pagi bersama kawan-kawan.','Mereka berdua bawa 7 kawan. Jumpa 5 kawan lain di sana. Berapa semua?','["13","14","15","16"]','14','2 + 7 + 5 = 14! Ramai solat raya!',17),
('7e09870d-88ab-4f7a-97a7-400efe9fa51d','00000000-0000-0000-0000-000000000005','Upin Ipin minta maaf kepada Opah dan Kak Ros pada hari raya.','Mereka minta maaf 4 orang pagi dan 3 orang petang. Berapa semua?','["6","7","8","9"]','7','4 + 3 = 7! Budak baik!',18),
('47c36a0d-14f6-4ec0-a626-19731b96a182','00000000-0000-0000-0000-000000000005','Ehsan beli baju raya paling mahal! Tapi dia kira baki duit.','Ehsan ada 20 ringgit. Baju berharga 13 ringgit. Berapa baki?','["5","6","7","8"]','7','20 - 13 = 7! Kira betul Ehsan!',19),
('8750b518-16ce-4c8e-ba15-7865b2c0545c','00000000-0000-0000-0000-000000000005','Semua kawan Upin Ipin kumpul untuk ambil gambar raya bersama!','Ada 6 kawan lelaki dan 8 kawan perempuan. Berapa semua yang bergambar?','["13","14","15","16"]','14','6 + 8 = 14! Gambar cantik!',20),
('2b9cc7a2-078e-46ac-9538-82062fba8fac','00000000-0000-0000-0000-000000000005','Upin Ipin simpan duit raya dalam tabung mereka.','Upin simpan 9 ringgit. Ipin simpan 8 ringgit. Berapa semua simpanan?','["15","16","17","18"]','17','9 + 8 = 17! Pandai menabung!',21),
('9b40645c-d34e-4c51-a46d-516eb56b81ad','00000000-0000-0000-0000-000000000005','Opah cerita tentang Hari Raya masa dia kecil dulu.','Opah cerita 12 kisah. Upin Ipin dengar 7 kisah. Berapa lagi?','["4","5","6","7"]','5','12 - 7 = 5! Cerita Opah best!',22),
('6bceda74-7260-4fa7-87a1-524f75007321','00000000-0000-0000-0000-000000000005','Jarjit buat nasyid raya. Semua orang nyanyi bersama!','Ada 15 orang nyanyi. 6 orang tak tahu lirik. Berapa yang tahu lirik?','["8","9","10","11"]','9','15 - 6 = 9! Nasyid meriah!',23),
('b26aa5cc-1ed1-497f-bbf6-f1645106a39d','00000000-0000-0000-0000-000000000005','Upin Ipin tolong Opah kemas rumah selepas tetamu balik.','Ada 19 perkara nak dikemas. Dah kemas 11. Berapa yang tinggal?','["7","8","9","10"]','8','19 - 11 = 8! Tolong Opah!',24),
('af60570d-ecc3-4cf0-9fcb-08736567801e','00000000-0000-0000-0000-000000000005','Mak Su beli kuih raya dari kedai untuk tambah stok.','Mak Su beli 8 bekas kuih cornflakes dan 9 bekas kuih tart. Berapa semua?','["15","16","17","18"]','17','8 + 9 = 17! Kuih berlambak!',25),
('e68601fb-4cb3-4bc9-b2d5-2f8364951c07','00000000-0000-0000-0000-000000000005','Upin Ipin buat kad raya untuk cikgu-cikgu mereka!','Mereka buat 7 kad untuk cikgu perempuan dan 5 kad untuk cikgu lelaki. Berapa semua?','["11","12","13","14"]','12','7 + 5 = 12! Budak baik!',26),
('e86f5ab5-2129-45a5-909a-600ded19bbb0','00000000-0000-0000-0000-000000000005','Semua orang rasa sedih bila Hari Raya nak habis. Tapi kenangan indah!','Hari Raya berlangsung 15 hari. Dah berlalu 9 hari. Berapa lagi?','["5","6","7","8"]','6','15 - 9 = 6! Nikmati lagi!',27),
('9aff3c75-2504-47fe-a71a-6e3d7f18c121','00000000-0000-0000-0000-000000000005','Upin Ipin kumpul semua duit raya dan kira bersama-sama!','Upin dapat 11 ringgit. Ipin dapat 8 ringgit. Berapa jumlah duit mereka?','["17","18","19","20"]','19','11 + 8 = 19! Banyaknya duit!',28),
('050d7095-ead7-4818-ae3f-6fce7484d81f','00000000-0000-0000-0000-000000000005','Opah doakan Upin Ipin pandai dalam pelajaran lepas Hari Raya.','Upin jawab 13 soalan. Betul 9. Berapa yang salah?','["3","4","5","6"]','4','13 - 9 = 4! Cuba lagi!',29),
('2b299ec8-7a26-4944-b4f9-c18d1782bbfb','00000000-0000-0000-0000-000000000005','Selamat Hari Raya! Upin dan Ipin gembira bersama keluarga!','Keluarga ada 6 orang. Jiran datang 9 orang. Berapa semua yang berkumpul?','["14","15","16","17"]','15','Selamat Hari Raya! Tahniah!',30);
