('bceb55fe-0f47-427b-a6e0-afb2c32e884e','00000000-0000-0000-0000-000000000007','Upin Ipin buat pelan belajar untuk peperiksaan tahun depan!','6 bulan × 8 jam belajar sebulan. Berapa jumlah jam belajar?','["46","47","48","49"]','48','6 × 8 = 48! Rancangan bagus!',25),
('df88916c-387f-4995-b299-eadfe1656cd6','00000000-0000-0000-0000-000000000007','Jam belajar dibahagi kepada semua subjek dengan bijaksana.','48 jam untuk 8 subjek. Setiap subjek dapat berapa jam?','["5","6","7","8"]','6','48 ÷ 8 = 6! Belajar terancang!',26),
('e5cae5f2-73c8-4258-9ad0-3f817b23c5cc','00000000-0000-0000-0000-000000000007','Cikgu Jasmin puji Upin Ipin di hadapan seluruh sekolah!','Ada 9 kelas. Setiap kelas ada 8 pelajar beri pujian. Berapa semua pujian?','["70","71","72","73"]','72','9 × 8 = 72! Bangga!',27),
('01eedcb4-1783-4c1d-9e16-39cada6009a1','00000000-0000-0000-0000-000000000007','Pujian dikira dan dibahagi sebagai galakan kepada semua pelajar.','72 pujian untuk 8 kelas. Setiap kelas dapat berapa pujian?','["8","9","10","11"]','9','72 ÷ 8 = 9! Motivasi tinggi!',28),
('39c3c406-51d1-4696-8f24-cb9bccb38c25','00000000-0000-0000-0000-000000000007','Upin Ipin terima hadiah buku terbaik dari Cikgu Jasmin!','Ada 7 hadiah. Setiap hadiah ada 9 buku. Berapa jumlah buku?','["61","62","63","64"]','63','7 × 9 = 63! Banyaknya buku!',29),
('1aa01f30-d523-4dea-bb52-e9add86918da','00000000-0000-0000-0000-000000000007','Musim periksa tamat! Upin Ipin jadi juara kelas! Tahniah!','63 bintang dibahagi 7 hari peperiksaan. Setiap hari dapat berapa bintang?','["8","9","10","11"]','9','Tahniah! Juara matematik!',30);
INSERT INTO public.questions (id, level_id, story_text, question_text, options, correct_answer, success_message, order_index) VALUES
('7f089af1-a2bc-4c95-a98a-5efcd382f3e3','00000000-0000-0000-0000-000000000008','Ejen Ali dapat misi paling susah! Dia kena pecahkan pangkalan musuh besar.','Pangkalan ada 1250 + 875 tentera. Berapa semua tentera?','["2100","2115","2125","2135"]','2125','1250 + 875 = 2125! Misi diterima!',1),
('0a02b896-6a00-402f-891c-7692ba47d039','00000000-0000-0000-0000-000000000008','MATA kerahkan ejen untuk serang pangkalan dari semua arah.','MATA ada 3000 ejen. Serang 1456. Berapa yang tunggu di belakang?','["1540","1544","1548","1554"]','1544','3000 - 1456 = 1544! Strategi tersusun!',2),
('ec67143c-6bf1-4034-9710-2394b6d316cf','00000000-0000-0000-0000-000000000008','Ali kesan kawasan rahsia musuh menggunakan MURI canggih.','MURI scan 2500 meter persegi. Jumpa kawasan 1375 meter. Baki yang belum scan?','["1123","1124","1125","1126"]','1125','2500 - 1375 = 1125! Scan terus!',3),
('af21d1a1-c83a-4602-a657-160e56040582','00000000-0000-0000-0000-000000000008','Ejen Dos koordinasi dengan pasukan dari utara dan selatan.','Pasukan utara ada 1650 orang. Pasukan selatan ada 2340. Berapa semua?','["3988","3989","3990","3991"]','3990','1650 + 2340 = 3990! Pasukan besar!',4),
('3ec2cafe-3338-4eb9-9383-fb16251812f2','00000000-0000-0000-0000-000000000008','Ali pecahkan kod dengan cepat! Setiap digit penting.','Kod musuh: 4 peringkat × 125 digit. Berapa jumlah digit?','["498","499","500","501"]','500','4 × 125 = 500! Kod berjaya dipecah!',5),
('09465823-ca8d-4994-bc33-109122eecf8e','00000000-0000-0000-0000-000000000008','MATA bahagi pasukan kepada unit khas untuk misi ini.','600 ejen dibahagi 24 unit. Setiap unit ada berapa ejen?','["23","24","25","26"]','25','600 ÷ 24 = 25! Unit sempurna!',6),
('f6f94158-4f7d-47db-a653-15618e0d96e7','00000000-0000-0000-0000-000000000008','Ejen Zain perlu koordinasi pelbagai jabatan dalam masa yang singkat.','Hantar 48 mesej kepada 3250 ejen. Berapa mesej per ejen?','["1","2","3","4"]','"1"','48... kira dahulu berapa untuk setiap kumpulan!',7),
('eb0e9e8e-fe6e-4265-b206-4ea3fc490933','00000000-0000-0000-0000-000000000008','Ali guna gadget untuk lacak pergerakan musuh dari jarak jauh.','Musuh bergerak 1200 meter ke timur dan 850 meter ke utara. Jumlah pergerakan?','["2048","2049","2050","2051"]','2050','1200 + 850 = 2050! Lacak berjaya!',8),
('5b90e3c1-d826-40a0-be6a-c8059d2742c5','00000000-0000-0000-0000-000000000008','Dokumen rahsia ditemui! Terdapat berbilang folder yang perlu diperiksa.','Ada 15 folder. Setiap folder ada 85 dokumen. Berapa semua dokumen?','["1273","1274","1275","1276"]','1275','15 × 85 = 1275! Banyak bukti!',9),
('e363d856-00d2-4f9e-bde3-f4258a1ee988','00000000-0000-0000-0000-000000000008','Dokumen dibahagi kepada jabatan penyiasatan untuk analisis.','1275 dokumen untuk 17 jabatan. Setiap jabatan dapat berapa?','["73","74","75","76"]','75','1275 ÷ 17 = 75! Kerja bermula!',10),
('bace77e1-497e-4965-b126-70913e11e2c0','00000000-0000-0000-0000-000000000008','Ali dan Dos rancang serangan akhir pada markas besar musuh!','Markas ada 2 peringkat × 675 bilik. Berapa jumlah bilik?','["1348","1349","1350","1351"]','1350','2 × 675 = 1350! Banyak bilik!',11),
('19c5112d-1523-4d14-a442-c5933091a496','00000000-0000-0000-0000-000000000008','Ejen dibahagi untuk geledah setiap bilik dalam masa yang sama.','1350 bilik untuk 27 pasukan. Setiap pasukan geledah berapa bilik?','["48","49","50","51"]','50','1350 ÷ 27 = 50! Sistematik!',12),
('68c04f6d-b7be-44a3-ab2c-4d7182c1aeb6','00000000-0000-0000-0000-000000000008','Ali jumpa ketua musuh! Pertarungan terakhir bermula!','Ketua musuh ada 3500 mata kesihatan. Serang dengan 1875. Berapa baki?','["1623","1624","1625","1626"]','1625','3500 - 1875 = 1625! Teruskan!',13),
('08c0dcb6-9798-407d-9d5e-6883d0afead9','00000000-0000-0000-0000-000000000008','Ali guna semua kuasanya dalam serangan bertubi-tubi!','Serangan pertama: 1250. Serangan kedua: 1625. Berapa jumlah kerosakan?','["2873","2874","2875","2876"]','2875','1250 + 1625 = 2875! Hampir menang!',14),
('45456a77-5537-4aad-b4bd-bed5b5aea7f6','00000000-0000-0000-0000-000000000008','Musuh kehabisan kuasa! Ali menghampiri kemenangan!','Baki ketua musuh: 3500 - 2875 = ?','["623","624","625","626"]','625','3500 - 2875 = 625! Hampir!',15),
('854c03b4-ed84-4f0a-8b43-3091d2fcda2d','00000000-0000-0000-0000-000000000008','Ali dapat bantuan dari Dos! Serangan gabungan!','Ali serang 450. Dos serang 325. Berapa jumlah serangan?','["773","774","775","776"]','775','450 + 325 = 775! Musuh jatuh!',16),
('55278ffd-72fa-40e2-864d-bbe634dc5d81','00000000-0000-0000-0000-000000000008','Ketua musuh hampir kalah! MATA hantar ejen sokongan.','Ejen sokongan: 18 kumpulan × 75 orang. Berapa jumlah?','["1348","1349","1350","1351"]','1350','18 × 75 = 1350! Bantuan tiba!',17),
('70320615-ed3a-4459-a6c7-4d6acdfa4703','00000000-0000-0000-0000-000000000008','Ejen sokongan dibahagi kepada kawasan yang paling kritikal.','1350 ejen untuk 54 kawasan. Setiap kawasan ada berapa ejen?','["23","24","25","26"]','25','1350 ÷ 54 = 25! Semua kawasan dijaga!',18),
('c8c97b82-0caf-4e01-8390-d92246162184','00000000-0000-0000-0000-000000000008','Misi hampir berjaya! Hitung jumlah musuh yang ditangkap.','Tangkap 2340 musuh. 875 lebih tangkap kemudian. Berapa semua?','["3213","3214","3215","3216"]','3215','2340 + 875 = 3215! Tangkap semua!',19),
('7a7f258b-5118-4adb-a6b3-31497bf7b557','00000000-0000-0000-0000-000000000008','Musuh ditahan dalam beberapa pusat tahanan sementara.','3215 musuh dalam 23 pusat. Setiap pusat ada berapa musuh?','["138","139","140","141"]','140','Kira: 3215 ÷ 23 ≈ 140! Tertahan!',20),
('d344cdda-98b3-4d62-b8e8-8ad11bccda29','00000000-0000-0000-0000-000000000008','Ali jumpa aset berharga musuh yang disembunyikan!','Nilai aset: RM 4500 + RM 3750. Berapa jumlah nilai?','["8248","8249","8250","8251"]','8250','4500 + 3750 = 8250! Harta ditemui!',21),
('27d816a1-d622-4cc3-8e8e-df10d1bb40df','00000000-0000-0000-0000-000000000008','Aset dikembalikan kepada pemilik asal yang sebenar.','Nilai aset RM 8250 dikembalikan kepada 25 mangsa. Setiap mangsa dapat berapa?','["328","329","330","331"]','330','8250 ÷ 25 = 330! Keadilan ditegak!',22),
('ed18022b-ed98-4bdc-b5cd-bf3bd38f5583','00000000-0000-0000-0000-000000000008','Ali tulis laporan lengkap tentang misi mustahil ini!','Laporan ada 36 bahagian. Setiap bahagian ada 125 patah perkataan. Berapa semua?','["4498","4499","4500","4501"]','4500','36 × 125 = 4500! Laporan lengkap!',23),
('e2bfbaee-e4e0-4de1-9042-88d89eda5e90','00000000-0000-0000-0000-000000000008','Laporan dikongsi dengan semua jabatan keselamatan negara.','4500 salinan untuk 90 jabatan. Setiap jabatan dapat berapa salinan?','["48","49","50","51"]','50','4500 ÷ 90 = 50! Semua diberitahu!',24),
('c462f2bb-ff54-40ca-ab1c-aec31cac9842','00000000-0000-0000-0000-000000000008','MATA hitung jumlah kredit yang Ali perolehi dalam misi ini!','Ali dapat 1750 kredit dalam misi ini. Kredit sebelum: 2650. Jumlah?','["4398","4399","4400","4401"]','4400','2650 + 1750 = 4400! Rekod baru!',25),
('38036217-ff9e-4f18-9bce-b430864a3415','00000000-0000-0000-0000-000000000008','Kredit Ali dibahagi mengikut kategori pencapaian berbeza.','4400 kredit dalam 8 kategori. Setiap kategori berapa kredit?','["548","549","550","551"]','550','4400 ÷ 8 = 550! Pencapaian tinggi!',26),
('70221c97-69b5-43a4-8c84-3cbd9a790dd3','00000000-0000-0000-0000-000000000008','MATA adakan majlis penghargaan untuk semua ejen yang terlibat!','Hadir 2500 orang. Meja makan ada 125 meja. Setiap meja berapa orang?','["18","19","20","21"]','20','2500 ÷ 125 = 20! Majlis meriah!',27),
('14e0625c-8421-4076-8b66-4ce48bdf3727','00000000-0000-0000-0000-000000000008','Hadiah diberikan kepada ejen-ejen terbaik dalam misi ini.','Hadiah bernilai: 20 × RM 450. Berapa jumlah nilai hadiah?','["8998","8999","9000","9001"]','9000','20 × 450 = 9000! Hadiah besar!',28),
('988c5837-9ecd-4f97-9426-1ee050a18eda','00000000-0000-0000-0000-000000000008','Ali terima anugerah terbaik MATA buat pertama kalinya!','Anugerah pertama dapat 3500 mata. Anugerah kedua dapat 2750 mata. Jumlah?','["6248","6249","6250","6251"]','6250','3500 + 2750 = 6250! Rekod dunia!',29),
('47bdb189-f7da-44ff-94a3-52294d7be707','00000000-0000-0000-0000-000000000008','Misi Mustahil berjaya! Ejen Ali adalah ejen terhebat sepanjang zaman!','6250 mata dibahagi 25 pencapaian. Setiap pencapaian berapa mata?','["248","249","250","251"]','250','Tahniah! 250 mata! Ali terhebat!',30);
INSERT INTO public.questions (id, level_id, story_text, question_text, options, correct_answer, success_message, order_index) VALUES
('ef4583fd-1772-4bfc-bc31-597705b88142','00000000-0000-0000-0000-000000000009','Upin dan Ipin bertanding jadi Juara Sekolah! Mereka kena score tinggi!','Markah Upin: 1250. Markah Ipin: 1375. Jumlah markah kembar?','["2623","2624","2625","2626"]','2625','1250 + 1375 = 2625! Kembar terhebat!',1),
('ca434a22-d064-46fe-aa26-203e8f3e9e62','00000000-0000-0000-0000-000000000009','Cikgu Jasmin bahagi soalan kepada semua peserta pertandingan.','2800 soalan untuk 56 peserta. Setiap peserta dapat berapa soalan?','["48","49","50","51"]','50','2800 ÷ 56 = 50! Adil cikgu!',2),
('a7f64bc4-f4e0-4884-9975-83dacd4e2eaa','00000000-0000-0000-0000-000000000009','Ehsan bersaing dengan Upin Ipin! Dia belajar lebih kuat dari biasa.','Ehsan belajar 45 jam dalam 9 minggu. Setiap minggu berapa jam?','["4","5","6","7"]','5','45 ÷ 9 = 5! Rajin Ehsan!',3),
('eb5c915e-7d07-48ee-9922-989360bcc89b','00000000-0000-0000-0000-000000000009','Markah semua peserta dikira selepas ujian pertama.','Ada 35 peserta. Jumlah markah 4550. Purata setiap peserta?','["128","129","130","131"]','130','4550 ÷ 35 = 130! Purata tinggi!',4),
('16ac90a4-6d30-4af1-84b8-19484e17c1ef','00000000-0000-0000-0000-000000000009','Ipin jawab soalan pecahan! Dia ingat apa yang Cikgu Jasmin ajar.','1/2 dari 840 buku ada di perpustakaan. Berapa buku di perpustakaan?','["418","419","420","421"]','420','1/2 × 840 = 420! Pandai Ipin!',5),
('900151f4-c62c-4bbd-aadb-0254427b71f5','00000000-0000-0000-0000-000000000009','Upin jawab soalan nombor besar dengan yakin!','Sekolah ada 1250 pelajar. 3/5 pergi aktiviti. Berapa yang pergi?','["748","749","750","751"]','750','3/5 × 1250 = 750! Betul!',6),
('baedeee8-e020-46c3-8cb3-e8b7055f682a','00000000-0000-0000-0000-000000000009','Fizi dapat soalan tentang pengukuran jarak. Dia guna formula.','Padang sekolah 480 meter × 95 meter. Berapa luas padang?','["45598","45599","45600","45601"]','45600','480 × 95 = 45600! Kira tepat!',7),
('440b1de1-795a-427d-b708-9f85f6a456ca','00000000-0000-0000-0000-000000000009','Jarjit kena bahagi masa untuk semua aktiviti sepanjang hari.','Sehari ada 24 jam. Tidur 8 jam. Baki untuk aktiviti dibahagi 4 slot. Setiap slot berapa jam?','["3","4","5","6"]','4','(24-8) ÷ 4 = 4! Bijak Jarjit!',8),
('80e14b9c-3e95-4c7e-bf13-3b8745e503b7','00000000-0000-0000-0000-000000000009','Upin Ipin kira markah gabungan dari semua ujian mereka.','Ujian 1: 1250. Ujian 2: 1475. Ujian 3: 1325. Jumlah semua?','["4048","4049","4050","4051"]','4050','1250 + 1475 + 1325 = 4050! Markah tinggi!',9),
('6fc69009-10f7-45c4-8d04-911c5b9ba231','00000000-0000-0000-0000-000000000009','Purata markah dikira untuk tentukan juara keseluruhan.','Jumlah 4050 dalam 3 ujian. Berapa purata setiap ujian?','["1348","1349","1350","1351"]','1350','4050 ÷ 3 = 1350! Purata cemerlang!',10),
('fcb9e67e-db9c-4c4c-ac27-2f5c867d4839','00000000-0000-0000-0000-000000000009','Mei Mei jawab soalan tentang belian di pasar. Dia guna matematik harian.','Beli 24 buku @ RM 4.50 sebuah. Berapa jumlah kos?','["RM 106","RM 107","RM 108","RM 109"]','"RM 108"','24 × 4.50 = RM108! Betul!',11),
('4ce6e863-db7f-48e4-8cfb-1935c79f5209','00000000-0000-0000-0000-000000000009','Baki wang dikira selepas membeli semua alatan yang diperlukan.','Ada RM 250. Beli barang RM 108. Berapa baki?','["RM 140","RM 141","RM 142","RM 143"]','"RM 142"','250 - 108 = RM142! Cermat berbelanja!',12),
('074992e0-751a-4fbd-a17a-5d166ee4f2cd','00000000-0000-0000-0000-000000000009','Ehsan kena kira bilangan patah perkataan dalam esei dia.','Esei ada 18 perenggan × 45 patah perkataan. Berapa jumlah patah perkataan?','["808","809","810","811"]','810','18 × 45 = 810! Esei panjang!',13),
('dbac08db-8956-454b-a83a-98fad8a30f5b','00000000-0000-0000-0000-000000000009','Patah perkataan dikira dan dinilai berdasarkan kualiti esei.','Esei 810 patah perkataan dinilai 9 aspek. Setiap aspek cover berapa patah perkataan?','["88","89","90","91"]','90','810 ÷ 9 = 90! Esei tersusun!',14),
('71b5a3e0-a3b9-40a5-8d3d-23bef0481d9d','00000000-0000-0000-0000-000000000009','Upin Ipin maju ke peringkat akhir! Saingan makin sengit!','Peringkat akhir ada 5 peserta. Markah keseluruhan 6500. Purata?','["1298","1299","1300","1301"]','1300','6500 ÷ 5 = 1300! Purata tinggi!',15),
('1645dd0d-2b7a-4ceb-924c-229d20df0805','00000000-0000-0000-0000-000000000009','Soalan peringkat akhir lebih susah! Tapi Upin Ipin tidak gentar!','Ada 4/5 dari 2500 soalan yang dijawab betul. Berapa soalan betul?','["1998","1999","2000","2001"]','2000','4/5 × 2500 = 2000! Cemerlang!',16),
('f11f8838-299c-41a3-932f-b279e00d9126','00000000-0000-0000-0000-000000000009','Opah berdoa dengan penuh harap untuk kejayaan Upin Ipin!','Opah doa 12 kali × 25 minit setiap kali. Berapa jumlah minit doa?','["298","299","300","301"]','300','12 × 25 = 300! Doa Opah penuh kasih!',17),
('970ea485-94ac-4754-93fa-5252e50c7283','00000000-0000-0000-0000-000000000009','Masa doa dikira dalam jam untuk rekod keluarga.','300 minit = berapa jam?','["4","5","6","7"]','5','300 ÷ 60 = 5 jam! Berkat doa Opah!',18),
('24734358-0489-4b4c-9e4e-c35fb1a152e0','00000000-0000-0000-0000-000000000009','Keputusan hampir diumumkan! Semua orang tegang!','Upin dapat 1450 markah. Ipin dapat 1375. Jumlah kembar?','["2823","2824","2825","2826"]','2825','1450 + 1375 = 2825! Kembar terbaik!',19),
('c1253dbe-dfca-4f0c-b797-ff68a6de31f1','00000000-0000-0000-0000-000000000009','Markah kembar dibandingkan dengan peserta lain.','Markah kembar: 2825. Markah lawan: 2650. Selisih berapa?','["173","174","175","176"]','175','2825 - 2650 = 175! Kembar menang!',20),
('12200b86-1cb3-4f63-b86d-b583feb1405a','00000000-0000-0000-0000-000000000009','Keputusan diumumkan! Upin dan Ipin MENANG! Semua orang bersorak!','Hadiah pertama bernilai RM 500. 1/4 untuk derma. Berapa untuk derma?','["RM 123","RM 124","RM 125","RM 126"]','"RM 125"','1/4 × 500 = RM125! Budak dermawan!',21),
('e55b3e29-e0ee-418a-9851-94e937fbbbb8','00000000-0000-0000-0000-000000000009','Baki hadiah digunakan untuk beli alatan belajar untuk sekolah.','Baki RM 375 dibeli alatan untuk 15 kumpulan. Setiap kumpulan dapat berapa?','["RM 23","RM 24","RM 25","RM 26"]','"RM 25"','375 ÷ 15 = RM25! Berkongsi!',22),
('414d716a-3d8c-49e0-8822-ce9557cadbf1','00000000-0000-0000-0000-000000000009','Kak Ros rakam video kemenangan Upin Ipin untuk kenangan keluarga!','Video 45 minit. Setiap 5 minit ada 1 babak. Berapa jumlah babak?','["7","8","9","10"]','9','45 ÷ 5 = 9! Kenangan indah!',23),
('e64fb2c4-4199-48af-903d-d948dfd9d61d','00000000-0000-0000-0000-000000000009','Upin Ipin buat ucapan kemenangan di hadapan seluruh sekolah!','Sekolah ada 1200 pelajar. 3/4 hadir mendengar ucapan. Berapa yang hadir?','["898","899","900","901"]','900','3/4 × 1200 = 900! Ramai hadir!',24),
('a2472395-f320-4c59-b1c6-d699082a3976','00000000-0000-0000-0000-000000000009','Majlis kemenangan diadakan di dewan sekolah yang besar!','Dewan ada 85 baris kerusi. Setiap baris ada 32 kerusi. Berapa semua kerusi?','["2718","2719","2720","2721"]','2720','85 × 32 = 2720! Semua boleh duduk!',25),
('5aed4f03-9cc6-4a00-912c-0880309c9be5','00000000-0000-0000-0000-000000000009','Kerusi dibahagi kepada beberapa bahagian mengikut kelas.','2720 kerusi untuk 34 kelas. Setiap kelas dapat berapa kerusi?','["78","79","80","81"]','80','2720 ÷ 34 = 80! Semua dapat tempat!',26),
('e9457e31-e9f3-4245-8ba8-053e5d308713','00000000-0000-0000-0000-000000000009','Cikgu Jasmin buat hadiah khas untuk semua peserta yang bertanding!','Ada 56 peserta. Hadiah bernilai RM 28 setiap satu. Berapa jumlah kos?','["1566","1567","1568","1569"]','1568','56 × 28 = RM1568! Murah hati!',27),
('a25905b8-19c3-45ac-8426-02fb863b2fc4','00000000-0000-0000-0000-000000000009','Wang hadiah dikira dari dana sekolah yang ada.','Dana sekolah RM 5000. Habis RM 1568. Berapa baki dana?','["3430","3431","3432","3433"]','3432','5000 - 1568 = RM3432! Baki cukup!',28),
('f4772071-1626-4576-9be3-32dff707924d','00000000-0000-0000-0000-000000000009','Opah masak kenduri besar untuk raikan kejayaan Upin Ipin!','Masak untuk 250 orang. Setiap orang makan 3/4 pinggan nasi. Berapa pinggan nasi semua?','["186","187","188","189"]','188','250 × 3/4 ≈ 188 pinggan! Banyaknya nasi!',29),
('19ce45b6-1935-4210-a501-531c4588914d','00000000-0000-0000-0000-000000000009','Tamat! Upin dan Ipin Juara Sekolah! Tahniah kepada kamu juga!','Jumlah bintang yang dikumpul: 1450 + 1375 + 1250 = ?','["4073","4074","4075","4076"]','4075','Tahniah! 4075 bintang! Kamu Juara!',30);
